mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rn, A.* FROM ( SELECT p.product_id AS productId, p.product_name AS productName, p.product_type AS productType, p.target_large AS targetLarge, p.target_detail AS targetDetail, TO_CHAR(DBMS_LOB.SUBSTR(p.product_desc, 1000, 1)) AS productDesc, p.rate_category AS rateCategory, p.is_active AS isActive, p.created_at AS createdAt, p.min_period_month AS minPeriodMonth, p.max_period_month AS maxPeriodMonth, p.min_amount AS minAmount, p.max_amount AS maxAmount, p.app_start_date AS appStartDate, p.app_end_date AS appEndDate, NVL(MIN(r.base_rate), 0) AS minRate, NVL(MAX(r.base_rate + NVL(r.preferential_rate, 0)), 0) AS maxRate FROM products p LEFT JOIN interest_rates r ON p.product_id = r.product_id AND r.is_active = 'Y' WHERE 1=1 AND p.is_active = 'Y' AND p.approve_status = '승인'
AND p.product_type IN ('FOREIGN_DEP', 'FOREIGN_SAV')
AND p.rate_category = #{rateCategory}
AND ( p.product_name LIKE '%' || #{keyword} || '%' OR DBMS_LOB.INSTR(p.product_desc, #{keyword}) > 0 )
AND p.product_type = #{productType}
AND ( p.target_large = #{targetLarge} OR p.target_large = 'ALL' )
AND ( p.target_detail = #{targetDetail} OR p.target_detail = 'ALL' )
GROUP BY p.product_id, p.product_name, p.product_type, p.target_large, p.target_detail, TO_CHAR(DBMS_LOB.SUBSTR(p.product_desc, 1000, 1)), p.rate_category, p.is_active, p.created_at, p.min_period_month, p.max_period_month, p.min_amount, p.max_amount, p.app_start_date, p.app_end_date
ORDER BY maxRate DESC
ORDER BY p.product_name ASC
ORDER BY p.created_at DESC
) A WHERE ROWNUM <= #{endRow} ) WHERE rn >= #{startRow}

        SELECT COUNT(*)
        FROM products p
        WHERE 1=1
          AND p.is_active = 'Y'
          AND p.approve_status = '승인'

		    AND p.product_type IN ('FOREIGN_DEP', 'FOREIGN_SAV')


		    AND p.rate_category = #{rateCategory}


            AND (
                p.target_large = #{targetLarge}
                OR p.target_large = 'ALL'
            )



            AND (
                p.target_detail = #{targetDetail}
                OR p.target_detail = 'ALL'
            )



            AND p.product_type = #{productType}



            AND (
                p.product_name LIKE '%' || #{keyword} || '%'
                OR DBMS_LOB.INSTR(p.product_desc, #{keyword}) > 0
            )
